import React from 'react';

const Header = ({ usuario, onLogout }) => {
  return (
    <header style={{
      backgroundColor: '#333',
      color: 'white',
      padding: '20px 40px',
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center'
    }}>
      <a href="/" style={{ textDecoration: 'none', color: 'white', cursor: 'pointer' }}>
        <h1 style={{ margin: 0 }}>Git-Academy</h1>
      </a>
      <div>
        {usuario ? (
          <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
            <span>Bienvenido, {usuario}</span>
            <button
              onClick={onLogout}
              style={{
                padding: '8px 16px',
                backgroundColor: '#dc3545',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: 'pointer'
              }}
            >
              Cerrar Sesión
            </button>
          </div>
        ) : (
          <a href="/signup" style={{ color: 'white', textDecoration: 'none' }}>
            Registrarse
          </a>
        )}
      </div>
    </header>
  );
};

export default Header;
